class Solution {
    public int findIntegers(int n) {
        int[] dp = new int[31];
        dp[0] = dp[1] = 1;
        for (int i = 2; i <= 30; i++) {
            dp[i] = dp[i - 1] + dp[i - 2];
        }
        int ans = 0, lastOne = -1;
        for (int i = 30; i >= 0; i--) {
            if ((n & (1 << i)) != 0) {
                ans += dp[i];
                if (lastOne == i - 1) break;
                lastOne = i;
            }
        }
        return ans + (n - (1 << lastOne) + 1);
    }
}
